import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreSurroundingSpaces_Default() {
        // Using the DEFAULT constant where ignoreSurroundingSpaces is false
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testGetIgnoreSurroundingSpaces_True() {
        // Using the withIgnoreSurroundingSpaces() method to get a new instance with ignoreSurroundingSpaces true
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(true);
        assertTrue(format.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testGetIgnoreSurroundingSpaces_False() {
        // Using the withIgnoreSurroundingSpaces(false) to explicitly set false
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(false);
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    public void testGetIgnoreSurroundingSpaces_ConstantTDF() {
        // TDF constant uses withIgnoreSurroundingSpaces() which sets it true
        CSVFormat format = CSVFormat.TDF;
        assertTrue(format.getIgnoreSurroundingSpaces());
    }
}
